class Solution:
    def waysToBuyPensPencils(self, total, cost1, cost2):
        # decompose over pencil count instead of pen count
        ways = 0
        pencils = 0
        while pencils * cost2 <= total:
            rem = total - pencils * cost2
            ways += rem // cost1 + 1
            pencils += 1
        return ways

